// ================================================================
// BUILD THE INVOICE HTML
//
// This node turns an order row from Google Sheets into the HTML
// page that becomes the PDF invoice.
//
// The node is set to "Run Once for Each Item", so this code runs
// separately for every new row — paste five rows into the sheet
// and five invoices go out.
//
// It is safe to edit this code. The places you are most likely
// to change are marked with:  CHANGE ME
// ================================================================


// ---- STEP 1: Get the current row ---------------------------------
// "$json" is this row from your sheet PLUS the settings from the
// "Workflow configuration" node (company name, tax rate, etc.)
const data = $json;


// ---- STEP 2: Helper that keeps the HTML safe --------------------
// This converts characters like < and & so that customer-entered
// text cannot break the invoice layout.
// Rule of thumb: wrap ANY text you print in the HTML in esc(...).
function esc(text) {
  return String(text ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');
}


// ---- STEP 3: Read the settings ----------------------------------
// These come from the "Workflow configuration" node.
// Edit them THERE (not here) so all your settings stay in one place.
const companyName = data.companyName || 'Your Company Inc.';
const logoUrl     = data.companyLogoUrl || '';
const taxRate     = Number(data.taxRate) || 0;      // 0.13 means 13%
const currency    = data.currencySymbol || '$';


// ---- STEP 4: Read the order row ---------------------------------
// The names in ['...'] must match your Google Sheets column
// headers EXACTLY. If your sheet uses different column names,
// change them here.                                    CHANGE ME
const orderNumber     = data['Order Number']     || 'INV-' + Date.now();
const customerName    = data['Customer Name']    || 'Customer';
const customerEmail   = data['Customer Email']   || '';
const customerAddress = data['Customer Address'] || '';
const dueDate         = data['Due Date']         || '';
const notes           = data['Notes']            || '';


// ---- STEP 5: Validate the line items ----------------------------
// The "Items" column must contain a JSON array, for example:
// [{"name":"Widget","quantity":2,"price":9.99}]
//
// IMPORTANT: a bad row must NOT stop the whole batch — other rows
// still deserve their invoices. Instead of stopping, this section
// marks the row as invalid; the If node after this one routes it
// to 'Mark order as failed', which writes the reason into the
// Status column of your sheet.
function invalidRow(reason) {
  return {
    json: {
      valid: false,
      orderNumber: data['Order Number'] || '',
      statusMessage: 'Error: ' + reason
    }
  };
}

if (data['Items'] === undefined) {
  return invalidRow('Items column not found — row 1 of the sheet must be the header row (see the sticky note)');
}

let items;
try {
  items = JSON.parse(data['Items']);
} catch (error) {
  return invalidRow('Items is not valid JSON — expected [{"name":...,"quantity":...,"price":...}]');
}
if (!Array.isArray(items) || items.length === 0) {
  return invalidRow('Items must be a non-empty JSON array');
}

// Every item needs a name, a quantity, and a price
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item || typeof item.name !== 'string' || item.name.trim() === '') {
    return invalidRow('item ' + (i + 1) + ' has no "name" field');
  }
  if (isNaN(Number(item.quantity)) || Number(item.quantity) <= 0) {
    return invalidRow('item ' + (i + 1) + ' needs a numeric quantity above zero');
  }
  if (isNaN(Number(item.price))) {
    return invalidRow('item ' + (i + 1) + ' needs a numeric price');
  }
}

// The email address is where the invoice goes — required
if (!customerEmail || !customerEmail.includes('@')) {
  return invalidRow('Customer Email is missing or not an email address');
}


// ---- STEP 6: Build the items table and the totals ---------------
let itemsHtml = '';   // one <tr> table row per item
let subtotal  = 0;

for (const item of items) {
  const quantity  = Number(item.quantity) || 0;
  const price     = Number(item.price) || 0;
  const lineTotal = quantity * price;
  subtotal = subtotal + lineTotal;

  itemsHtml = itemsHtml +
    '<tr>' +
      '<td>' + esc(item.name) + '</td>' +
      '<td>' + quantity + '</td>' +
      '<td>' + currency + price.toFixed(2) + '</td>' +
      '<td>' + currency + lineTotal.toFixed(2) + '</td>' +
    '</tr>';
}

const tax   = subtotal * taxRate;
const total = subtotal + tax;


// ---- STEP 7: Build the optional sections ------------------------
// Each of these is only shown when there is something to show.

// Company logo in the header (only if a logo URL is configured)
let logoHtml = '';
if (logoUrl) {
  logoHtml = '<img src="' + esc(logoUrl) + '" style="max-height:60px;max-width:200px;" alt="Logo">';
}

// Tax line (only if the tax rate is above zero)
let taxHtml = '';
if (taxRate > 0) {
  taxHtml = '<p class="right">Tax (' + (taxRate * 100).toFixed(0) + '%): ' + currency + tax.toFixed(2) + '</p>';
}

// Due date, address, and notes (only if the row has them)
let dueHtml = '';
if (dueDate) {
  dueHtml = '<p><strong>Due Date:</strong> ' + esc(dueDate) + '</p>';
}

let addressHtml = '';
if (customerAddress) {
  addressHtml = '<p><strong>Address:</strong> ' + esc(customerAddress) + '</p>';
}

let notesHtml = '';
if (notes) {
  notesHtml = '<div class="notes"><strong>Notes:</strong><br>' + esc(notes) + '</div>';
}


// ---- STEP 8: The invoice itself ---------------------------------
// This is normal HTML and CSS. Change colors, fonts, and layout
// in the <style> block below.                          CHANGE ME
const html = `<!DOCTYPE html>
<html>
<head>
<style>
  body        { font-family: Arial, sans-serif; padding: 40px; color: #1e293b; }
  .header     { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 24px; }
  h1          { margin: 0 0 4px 0; }
  h2          { color: #64748b; margin: 0; font-weight: 600; }
  table       { width: 100%; border-collapse: collapse; margin: 20px 0; }
  th, td      { padding: 10px; text-align: left; border-bottom: 1px solid #e2e8f0; }
  th          { background: #f1f5f9; }
  .right      { text-align: right; }
  .bold       { font-weight: bold; font-size: 18px; }
  .notes      { margin-top: 30px; padding: 15px; background: #f8fafc; border-left: 3px solid #cbd5e1; }
</style>
</head>
<body>

  <div class="header">
    <div>
      <h1>${esc(companyName)}</h1>
      <h2>INVOICE</h2>
    </div>
    ${logoHtml}
  </div>

  <p><strong>Invoice #:</strong> ${esc(orderNumber)}</p>
  <p><strong>Date:</strong> ${new Date().toISOString().slice(0, 10)}</p>
  ${dueHtml}
  <p><strong>Bill To:</strong> ${esc(customerName)}</p>
  ${addressHtml}
  <p><strong>Email:</strong> ${esc(customerEmail)}</p>

  <table>
    <tr><th>Item</th><th>Qty</th><th>Price</th><th>Total</th></tr>
    ${itemsHtml}
  </table>

  <p class="right">Subtotal: ${currency}${subtotal.toFixed(2)}</p>
  ${taxHtml}
  <p class="right bold">Total: ${currency}${total.toFixed(2)}</p>

  ${notesHtml}

</body>
</html>`;


// ---- STEP 9: Hand everything to the next nodes -------------------
// "html" becomes the PDF. The other fields are used by the
// email, Drive, and sheet-update nodes further down the line.
// (One item out per row in — the next nodes run once per invoice.)
return {
  json: {
    valid: true,
    html: html,
    orderNumber: orderNumber,
    customerName: customerName,
    customerEmail: customerEmail,
    invoiceFilename: orderNumber + '.pdf',
    emailSubject: (data.emailSubjectPrefix || 'Your invoice') + ' — ' + orderNumber
  }
};
